with t as (select id,row_number() over(order by name) rn from teams), p as (select id,row_number() over(order by created_at,display_name) rn from participants where profile_id is null) insert into team_members(team_id,participant_id) select t.id,p.id from p join t on t.rn=((p.rn-1)/3)+1 on conflict do nothing;
with r as (select id from rounds where number=1) insert into matches(round_id,match_order,competition,home_team,away_team,starts_at,division,is_pleno) select r.id,g,case when g%2=0 then 'LaLiga EA Sports' else 'LaLiga Hypermotion' end,'Local '||g,'Visitante '||g,'2026-08-22 18:00+00',case when g%2=0 then 'primera' else 'segunda' end,g=14 from r, generate_series(1,14) g on conflict (round_id,match_order) do nothing;
