insert into teams(name,color) values ('Equipo 1','#0ea5e9'),('Equipo 2','#22c55e'),('Equipo 3','#f97316'),('Equipo 4','#a855f7') on conflict (name) do nothing;
insert into participants(display_name,official,status) select unnest(array['José','Ana','Luis','Marta','Pablo','Laura','Diego','Sofía','Javi','Carmen','Raúl','Elena']),true,'active';
insert into rounds(number,name,status,published_at,deadline_at) values (1,'Jornada inaugural','published','2026-08-15 12:00+00','2026-08-21 20:00+00') on conflict (number) do nothing;
insert into round_qualified_participants(round_id,participant_id) select r.id,p.id from rounds r cross join participants p where r.number=1 and p.status='active' on conflict do nothing;
